import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import { TemaProvider } from './context/TemaContext';
import { CarritoProvider } from './context/CarritoContext';
import Home from './pages/Home';
import Ciberseguridad from './pages/Ciberseguridad';
import './App.css';

const App = () => {
  return (
    <TemaProvider>
      <CarritoProvider>
        <BrowserRouter>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/ciberseguridad" element={<Ciberseguridad />} />
            <Route path="*" element={<h1 style={{ color: '#ff00ff', textAlign: 'center', marginTop: '100px' }}>Error 404: Página no encontrada</h1>} />
          </Routes>
        </BrowserRouter>
      </CarritoProvider>
    </TemaProvider>
  );
};

export default App;
